INSERT INTO survey_questions VALUES ('802951e3-7d52-4e05-8b3f-d1fc1c4a5e52', 0, '0분기(~1개월)', '사전 온보딩 (Pre-Onboarding)', '첫인상 형성과 기대 조정', '팀내 인원들의 이름과 직급을 다 외웠는가', '사내 메일과 장비들을 받았는가', '업무를 시작할 환경이 다 갖추어졌는가', '적응해 나아가는 본인의 모습을 상상하여 앞으로의 포부를 간단하게 적어주세요');
INSERT INTO survey_questions VALUES ('ce410154-ba7e-40da-a4e7-683ce0359bba', 1, '1분기(1개월~2개월)', '조직 적응 (Cultural Onboarding)', '조직 문화와 가치 내재화', '회사의 미션과 가치를 이해하는가', '업무 장비 및 권한이 적절한가', '질문하기 편한 분위기인가', '입사 전 기대치와 실제 조직 문화의 차이는?');
INSERT INTO survey_questions VALUES ('d26c4144-c986-42ad-8aba-0fc85c53838b', 2, '2분기(2개월~4개월)', '역할 및 기대치 명확화 (Role Clarity & Performance Expectation)', '역할 이해 및 업무 수행 시작', '본인의 R&R이 명확한가', '업무 프로세스에 적응했는가', '본인의 역량을 발휘하고 있는가', '최근 3개월간 가장 뿌듯했던 업무 경험은?');
INSERT INTO survey_questions VALUES ('e6f7caf9-3936-4cfd-aeb1-44caa89e18a3', 3, '3분기(4개월~6개월)', '네트워킹 및 협업 (Building Internal Networks)', '조직 내 관계 형성', '타 부서와의 소통이 원활한가', '비즈니스 흐름을 파악하고 있는가', '문제 해결 시 자율성이 보장되는가', '협업 과정에서 개선이 필요한 시스템은?');
INSERT INTO survey_questions VALUES ('5f848a20-e92a-49d8-93f5-42d2bfa41f82', 4, '4분기(6개월~1년)', '업무 지원 및 성장 (Continuous Learning & Development)', '장기적 성장 및 정착', '1년 뒤 본인의 성장 모습이 그려지는가', '지인에게 입사를 추천할 의향이 있는가', '온보딩이 업무에 도움이 되었는가', '앞으로 새롭게 들어올 신입 사원들을 위한 꿀팁 한마디');
